#include <stdio.h>
#include <stdlib.h>
#define MAX 100005
typedef struct { int u, v; } Edge;
int diameter(int **graph, int N) {
    int *dist = (int *)calloc(N, sizeof(int));
    for (int i = 0; i < N; i++) {
        dist[i] = -1;
    }
    dist[0] = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (graph[i][j] == 1 && dist[j] == -1) {
                dist[j] = dist[i] + 1;
            }
        }
    }
    int max = 0;
    for (int i = 0; i < N; i++) {
        if (dist[i] > max) {
            max = dist[i];
        }
    }
    free(dist);
    return max;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int **graph = (int **)calloc(N, sizeof(int *));
        for (int i = 0; i < N; i++) {
            graph[i] = (int *)calloc(N, sizeof(int));
        }
        for (int i = 0; i < M; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            graph[u - 1][v - 1] = 1;
            graph[v - 1][u - 1] = 1;
            printf("%d\n", diameter(graph, N));
        }
        for (int i = 0; i < N; i++) {
            free(graph[i]);
        }
        free(graph);
    }
    return 0;
}

