function diameter(graph, N) {
    let dist = new Array(N).fill(-1);
    dist[0] = 0;
    for (let i = 0; i < N; i++) {
        for (let j = 0; j < N; j++) {
            if (graph[i][j] === 1 && dist[j] === -1) {
                dist[j] = dist[i] + 1;
            }
        }
    }
    return Math.max(...dist);
